{
  "compilerOptions": {
    "target": "ES2020",
    "module": "ESNext",
    "lib": ["ES2020", "DOM"],
    "skipLibCheck": true,
    "esModuleInterop": true,
    "allowSyntheticDefaultImports": true,
    "strict": true,
    "forceConsistentCasingInFileNames": true,
    "noEmitOnError": true
  }
}

// ❌ Bad - Creates complex inferred types
const config = {
  a: { b: { c: { d: { e: 1 } } } }
};

// ✅ Good - Explicit typing prevents deep inference
interface Config {
  a: {
    b: {
      c: number;
    };
  };
}

const config: Config = {
  a: { b: { c: 1 } }
};

// More specific, narrower types
const routes = {
  home: '/home',
  about: '/about',
  contact: '/contact'
} as const;

// Type is: { readonly home: '/home'; readonly about: '/about'; ... }

// webpack.config.js
module.exports = {
  optimization: {
    splitChunks: {
      chunks: 'all',
      cacheGroups: {
        vendor: {
          test: /[\\/]node_modules[\\/]/,
          name: 'vendors',
          chunks: 'all',
        },
      },
    },
  },
};

// Use dynamic imports
const HeavyComponent = await import('./HeavyComponent');

