// Measure type inference performance
interface User {
  id: number;
  name: string;
  email: string;
  createdAt: Date;
}

// ❌ Slow with large unions
type Status = 'pending' | 'active' | 'inactive' | 'deleted' | 'banned' | 'suspended';

// ✅ Fast with enums for many values
enum StatusEnum {
  PENDING = 'pending',
  ACTIVE = 'active',
  INACTIVE = 'inactive',
  DELETED = 'deleted',
  BANNED = 'banned',
  SUSPENDED = 'suspended'
}

// Test performance
const users: User[] = [];
for (let i = 0; i < 1000; i++) {
  users.push({
    id: i,
    name: `User ${i}`,
    email: `user${i}@example.com`,
    createdAt: new Date()
  });
}

console.log(`Created ${users.length} users`);
